alternative fix:
```patch
diff --git a/pkg/api/handlers/compat/images_push.go b/pkg/api/handlers/compat/images_push.go
index a5e63383f7..c2fed1389b 100644
--- a/pkg/api/handlers/compat/images_push.go
+++ b/pkg/api/handlers/compat/images_push.go
@@ -189,21 +189,23 @@ loop: // break out of for/select infinite loop
 			flush()
 		case err := <-pushErrChan:
 			if err != nil {
-				var msg string
+				var code = http.StatusInternalServerError
 				if errors.Is(err, storage.ErrImageUnknown) {
 					// Image may have been removed in the meantime.
-					writeStatusCode(http.StatusNotFound)
-					msg = "An image does not exist locally with the tag: " + imageName
-				} else {
-					writeStatusCode(http.StatusInternalServerError)
-					msg = err.Error()
+					code = http.StatusNotFound
+					err = errors.New("An image does not exist locally with the tag: " + imageName)
+				}
+				if !statusWritten {
+					utils.Error(w, code, err)
+					flush()
+					break loop
 				}
 				report.Error = &jsonstream.Error{
-					Message: msg,
+					Message: err.Error(),
 				}
 				//nolint:staticcheck // Deprecated field, but because consumers might still read it keep it.
 				if _, err := apiutil.SupportedVersion(r, "<1.52.0"); err == nil {
-					report.ErrorMessage = msg
+					report.ErrorMessage = err.Error()
 				}
 				if err := enc.Encode(report); err != nil {
 					logrus.Warnf("Failed to json encode error %q", err.Error())
```

I like the alternative fix, but I would propose saving the error to a different variable instead of keeping it in `err`, because `if _, err := apiutil.SupportedVersion(r, "<1.52.0"); err == nil {` overwrites the error with `nil` before `report.ErrorMessage = err.Error()` happens.

```patch
diff --git a/pkg/api/handlers/compat/images_push.go b/pkg/api/handlers/compat/images_push.go
index a5e63383f7..5e3a4fc1bf 100644
--- a/pkg/api/handlers/compat/images_push.go
+++ b/pkg/api/handlers/compat/images_push.go
@@ -189,21 +189,24 @@ loop: // break out of for/select infinite loop
                        flush()
                case err := <-pushErrChan:
                        if err != nil {
-                               var msg string
+                               statusCode := http.StatusInternalServerError
+                               pushError := err
                                if errors.Is(err, storage.ErrImageUnknown) {
                                        // Image may have been removed in the meantime.
-                                       writeStatusCode(http.StatusNotFound)
-                                       msg = "An image does not exist locally with the tag: " + imageName
-                               } else {
-                                       writeStatusCode(http.StatusInternalServerError)
-                                       msg = err.Error()
+                                       statusCode = http.StatusNotFound
+                                       pushError = errors.New("An image does not exist locally with the tag: " + imageName)
+                               }
+                               if !statusWritten {
+                                       utils.Error(w, statusCode, pushError)
+                                       flush()
+                                       break loop
                                }
                                report.Error = &jsonstream.Error{
-                                       Message: msg,
+                                       Message: pushError.Error(),
                                }
                                //nolint:staticcheck // Deprecated field, but because consumers might still read it keep it.
                                if _, err := apiutil.SupportedVersion(r, "<1.52.0"); err == nil {
-                                       report.ErrorMessage = msg
+                                       report.ErrorMessage = pushError.Error()
                                }
                                if err := enc.Encode(report); err != nil {
                                        logrus.Warnf("Failed to json encode error %q", err.Error())

```

